import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.y1bVONfd.js";const g=JSON.parse('{"title":"Knowledge Base","description":"Enterprise knowledge management with RAG-powered context injection","frontmatter":{"title":"Knowledge Base","description":"Enterprise knowledge management with RAG-powered context injection"},"headers":[],"relativePath":"guide/knowledge-base.md","filePath":"guide/knowledge-base.md"}'),r={name:"guide/knowledge-base.md"};function o(i,e,d,l,p,c){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="knowledge-base" tabindex="-1">Knowledge Base <a class="header-anchor" href="#knowledge-base" aria-label="Permalink to &quot;Knowledge Base&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>WebRouter&#39;s knowledge base system captures, stores, and retrieves organizational knowledge — then automatically injects relevant context into LLM requests. It combines automatic knowledge capture from conversations with RAG (Retrieval-Augmented Generation) for real-time context injection.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐     ┌──────────────┐     ┌──────────────┐</span></span>
<span class="line"><span>│  Knowledge    │     │  Knowledge    │     │  RAG          │</span></span>
<span class="line"><span>│  Capture      │     │  Extraction   │     │  Injection    │</span></span>
<span class="line"><span>│  (auto)       │     │  (LLM)        │     │  (real-time)  │</span></span>
<span class="line"><span>└──────┬───────┘     └──────┬───────┘     └──────┬───────┘</span></span>
<span class="line"><span>       │                    │                    │</span></span>
<span class="line"><span>       ▼                    ▼                    ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_knowledge_raw                     │</span></span>
<span class="line"><span>│  Raw conversation snippets captured from chat         │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │ LLM extraction</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_agent_memory                      │</span></span>
<span class="line"><span>│  Structured facts &amp; preferences extracted from raw    │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │ Embedding</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_knowledge_vectors                 │</span></span>
<span class="line"><span>│  Vector embeddings for semantic search                │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>               RAG Context Injection</span></span>
<span class="line"><span>           (injected into system prompt)</span></span></code></pre></div><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><h3 id="_1-knowledge-capture-automatic" tabindex="-1">1. Knowledge Capture (Automatic) <a class="header-anchor" href="#_1-knowledge-capture-automatic" aria-label="Permalink to &quot;1. Knowledge Capture (Automatic)&quot;">​</a></h3><p>When a token has <code>KnowledgeCaptureEnabled</code>, every conversation turn is automatically captured:</p><ul><li><strong>Non-streaming</strong>: Full request/response pairs saved after completion</li><li><strong>Streaming</strong>: Accumulated content saved after stream ends</li><li>Content is stored in <code>wr_knowledge_raw</code> for later extraction</li></ul><p>Enable per token under <strong>Tokens</strong> → <strong>Knowledge Capture</strong>.</p><h3 id="_2-knowledge-extraction-llm-powered" tabindex="-1">2. Knowledge Extraction (LLM-Powered) <a class="header-anchor" href="#_2-knowledge-extraction-llm-powered" aria-label="Permalink to &quot;2. Knowledge Extraction (LLM-Powered)&quot;">​</a></h3><p>Raw captured conversations are processed by an LLM to extract structured knowledge:</p><ul><li>Facts, preferences, decisions, and procedures</li><li>Stored in <code>wr_agent_memory</code> as structured entries</li><li>Supports batch extraction and incremental processing</li></ul><p>Trigger extraction via:</p><ul><li><strong>Admin panel</strong>: Knowledge → Extract</li><li><strong>API</strong>: <code>POST /admin/knowledge_extract</code></li></ul><h3 id="_3-rag-injection-real-time" tabindex="-1">3. RAG Injection (Real-Time) <a class="header-anchor" href="#_3-rag-injection-real-time" aria-label="Permalink to &quot;3. RAG Injection (Real-Time)&quot;">​</a></h3><p>Before each request, if RAG is enabled for the token:</p><ol><li>Extract the user&#39;s query from the request</li><li>Vectorize and search <code>wr_knowledge_vectors</code></li><li>Retrieve top-K relevant chunks</li><li>Inject matching context into the system prompt</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System: You are a helpful assistant.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Knowledge Base Context]</span></span>
<span class="line"><span>Relevant information from the knowledge base:</span></span>
<span class="line"><span>- Fact 1: ...</span></span>
<span class="line"><span>- Fact 2: ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: What&#39;s our deployment process?</span></span></code></pre></div><h2 id="configuration-per-token" tabindex="-1">Configuration Per Token <a class="header-anchor" href="#configuration-per-token" aria-label="Permalink to &quot;Configuration Per Token&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>rag_enabled</code></td><td>false</td><td>Enable RAG context injection</td></tr><tr><td><code>rag_top_k</code></td><td>3</td><td>Number of chunks to retrieve</td></tr><tr><td><code>rag_min_relevance</code></td><td>0.7</td><td>Minimum similarity threshold</td></tr><tr><td><code>rag_hybrid_alpha</code></td><td>0</td><td>Hybrid search weight (0 = pure vector, &gt;0 = BM25 + vector)</td></tr><tr><td><code>rag_reranker</code></td><td>none</td><td>Reranking model for result refinement</td></tr><tr><td><code>system_prompt_knowledge</code></td><td>&quot;&quot;</td><td>Static knowledge to always inject</td></tr><tr><td><code>knowledge_department</code></td><td>&quot;&quot;</td><td>Department filter for domain-scoped search</td></tr><tr><td><code>knowledge_capture_enabled</code></td><td>false</td><td>Auto-capture conversations</td></tr></tbody></table><h2 id="chunking-strategies" tabindex="-1">Chunking Strategies <a class="header-anchor" href="#chunking-strategies" aria-label="Permalink to &quot;Chunking Strategies&quot;">​</a></h2><p>Documents are chunked before embedding using configurable strategies:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Description</th></tr></thead><tbody><tr><td><code>fixed</code></td><td>Split by fixed character count with overlap</td></tr><tr><td><code>sentence</code></td><td>Split at sentence boundaries</td></tr><tr><td><code>paragraph</code></td><td>Split at paragraph boundaries</td></tr></tbody></table><h2 id="hybrid-search" tabindex="-1">Hybrid Search <a class="header-anchor" href="#hybrid-search" aria-label="Permalink to &quot;Hybrid Search&quot;">​</a></h2><p>When <code>rag_hybrid_alpha &gt; 0</code>, wr-proxy combines:</p><ul><li><strong>Vector search</strong> — semantic similarity via embeddings</li><li><strong>BM25 keyword search</strong> — exact term matching</li></ul><p>The alpha parameter controls the blend (0 = pure vector, 1 = pure BM25).</p><h2 id="department-scoping" tabindex="-1">Department Scoping <a class="header-anchor" href="#department-scoping" aria-label="Permalink to &quot;Department Scoping&quot;">​</a></h2><p>Organize knowledge by department for multi-team deployments:</p><ol><li>Set <code>knowledge_department</code> on each token (e.g., &quot;engineering&quot;, &quot;marketing&quot;)</li><li>RAG searches are scoped to the token&#39;s department</li><li>Falls back to global search if department results are empty</li></ol><h2 id="management-endpoints" tabindex="-1">Management Endpoints <a class="header-anchor" href="#management-endpoints" aria-label="Permalink to &quot;Management Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET /admin/knowledge_stats</code></td><td>Knowledge base statistics</td></tr><tr><td><code>POST /admin/knowledge_analyze</code></td><td>Analyze knowledge quality</td></tr><tr><td><code>POST /admin/knowledge_extract</code></td><td>Trigger LLM extraction</td></tr><tr><td><code>POST /admin/knowledge_embedding_backfill</code></td><td>Backfill vector embeddings</td></tr><tr><td><code>GET /admin/knowledge_rag_stats</code></td><td>RAG hit/miss statistics</td></tr><tr><td><code>GET /admin/knowledge_prompt_preview</code></td><td>Preview injected prompt</td></tr></tbody></table>`,33)])])}const u=t(r,[["render",o]]);export{g as __pageData,u as default};
